     1→//! High-level statistical modeling API for Rust
     2→//!
     3→//! This crate provides familiar model-fitting APIs like `Lm` (Linear Models)
     4→//! and `Glm` (Generalized Linear Models), integrating lower-level crates
     5→//! to provide a complete modeling workflow.
     6→
     7→#![forbid(unsafe_code)]
     8→#![warn(missing_docs)]
     9→
    10→use faer::{prelude::*, Mat};
    11→
    12→/// Statistical modeling errors
    13→#[derive(thiserror::Error, Debug)]
    14→pub enum ModelError {
    15→    /// Linear algebra computation error
    16→    #[error("Linear algebra error: {0}")]
    17→    LinearAlgebra(String),
    18→    /// Invalid model specification
    19→    #[error("Invalid model: {0}")]
    20→    InvalidModel(String),
    21→}
    22→
    23→/// Common trait for all fitted models
    24→pub trait Fit {
    25→    /// Get model coefficients
    26→    fn coefficients(&self) -> &[f64];
    27→
    28→    /// Get fitted values
    29→    fn fitted(&self) -> &[f64];
    30→
    31→    /// Get residuals
    32→    fn residuals(&self) -> &[f64];
    33→
    34→    /// Get model summary
    35→    fn summary(&self) -> ModelSummary;
    36→}
    37→
    38→/// Model summary information
    39→#[derive(Debug)]
    40→pub struct ModelSummary {
    41→    /// Coefficient table
    42→    pub coefficients: Vec<CoefficientRow>,
    43→    /// R-squared (coefficient of determination)
    44→    pub r_squared: f64,
    45→    /// Adjusted R-squared
    46→    pub adj_r_squared: f64,
    47→    /// Residual standard error
    48→    pub residual_std_error: f64,
    49→    /// F-statistic for overall model significance
    50→    pub f_statistic: f64,
    51→    /// p-value for F-statistic
    52→    pub f_p_value: f64,
    53→    /// Degrees of freedom for model (number of predictors excluding intercept)
    54→    pub df_model: usize,
    55→    /// Degrees of freedom for residuals
    56→    pub df_residual: usize,
    57→}
    58→
    59→/// A row in the coefficient table
    60→#[derive(Debug)]
    61→pub struct CoefficientRow {
    62→    /// Variable name
    63→    pub name: String,
    64→    /// Estimated coefficient
    65→    pub estimate: f64,
    66→    /// Standard error
    67→    pub std_error: f64,
    68→    /// t-statistic
    69→    pub t_value: f64,
    70→    /// p-value
    71→    pub p_value: f64,
    72→}
    73→
    74→/// Linear model fitting
    75→pub struct Lm;
    76→
    77→/// Fitted linear model results
    78→#[derive(Debug)]
    79→pub struct LmFit {
    80→    coefficients: Vec<f64>,
    81→    fitted_values: Vec<f64>,
    82→    residuals: Vec<f64>,
    83→    /// Number of observations
    84→    n_obs: usize,
    85→    /// Matrix rank (for rank-deficient matrices)
    86→    rank: usize,
    87→    /// Design matrix for statistical inference (stored for covariance calculation)
    88→    x_matrix: Mat<f64>,
    89→}
    90→
    91→impl Lm {
    92→    /// Fit a linear model using QR decomposition with column pivoting
    93→    ///
    94→    /// This implementation uses faer's column-pivoted QR decomposition to handle
    95→    /// rank-deficient design matrices robustly, as is common in statistical modeling.
    96→    pub fn fit(
    97→        x_data: &[f64],
    98→        y_data: &[f64],
    99→        n_rows: usize,
   100→        n_cols: usize,
   101→    ) -> Result<LmFit, ModelError> {
   102→        if x_data.len() != n_rows * n_cols {
   103→            return Err(ModelError::InvalidModel(
   104→                "Design matrix dimensions don't match data".to_string(),
   105→            ));
   106→        }
   107→
   108→        if y_data.len() != n_rows {
   109→            return Err(ModelError::InvalidModel(
   110→                "Response vector length doesn't match number of observations".to_string(),
   111→            ));
   112→        }
   113→
   114→        // Create faer matrices from input data
   115→        let x_mat = Mat::from_fn(n_rows, n_cols, |i, j| x_data[i * n_cols + j]);
   116→        let y_mat = Mat::from_fn(n_rows, 1, |i, _| y_data[i]);
   117→
   118→        // Use column-pivoted QR for numerical stability with rank-deficient matrices
   119→        let qr = x_mat.col_piv_qr();
   120→
   121→        // Calculate rank from R matrix diagonal elements
   122→        let r_matrix = qr.R();
   123→        let tolerance = 1e-12;
   124→        let mut rank = 0;
   125→        for i in 0..r_matrix.nrows().min(r_matrix.ncols()) {
   126→            if r_matrix[(i, i)].abs() > tolerance {
   127→                rank += 1;
   128→            }
   129→        }
   130→
   131→        // Handle rank-deficient matrices by checking for numerical instability
   132→        let coefficients_mat = qr.solve_lstsq(&y_mat);
   133→
   134→        // Check for numerical instability and apply correction if needed
   135→        let has_instability =
   136→            (0..coefficients_mat.nrows()).any(|i| coefficients_mat[(i, 0)].abs() > 1e10);
   137→
   138→        let final_coefficients_mat = if has_instability {
   139→            // For rank-deficient case, set coefficients for columns beyond rank to zero
   140→            let mut corrected_coefs = Vec::new();
   141→            for i in 0..coefficients_mat.nrows() {
   142→                let coef = coefficients_mat[(i, 0)];
   143→                if coef.abs() > 1e10 {
   144→                    corrected_coefs.push(0.0);
   145→                } else {
   146→                    corrected_coefs.push(coef);
   147→                }
   148→            }
   149→            Mat::from_fn(n_cols, 1, |i, _| corrected_coefs[i])
   150→        } else {
   151→            coefficients_mat
   152→        };
   153→
   154→        // Calculate fitted values: ŷ = X * β (using corrected coefficients)
   155→        let fitted_mat = &x_mat * &final_coefficients_mat;
   156→
   157→        // Calculate residuals: e = y - ŷ
   158→        let residuals_mat = &y_mat - &fitted_mat;
   159→
   160→        // Extract results to plain Vec<f64> for API
   161→        let coefficients: Vec<f64> = (0..final_coefficients_mat.nrows())
   162→            .map(|i| final_coefficients_mat[(i, 0)])
   163→            .collect();
   164→
   165→        let fitted_values: Vec<f64> = (0..fitted_mat.nrows())
   166→            .map(|i| fitted_mat[(i, 0)])
   167→            .collect();
   168→
   169→        let residuals: Vec<f64> = (0..residuals_mat.nrows())
   170→            .map(|i| residuals_mat[(i, 0)])
   171→            .collect();
   172→
   173→        // rank is already computed above using qr.rank()
   174→
   175→        Ok(LmFit {
   176→            coefficients,
   177→            fitted_values,
   178→            residuals,
   179→            n_obs: n_rows,
   180→            rank,
   181→            x_matrix: x_mat,
   182→        })
   183→    }
   184→}
   185→
   186→impl LmFit {
   187→    /// Get the number of observations used in the model
   188→    pub fn n_obs(&self) -> usize {
   189→        self.n_obs
   190→    }
   191→
   192→    /// Get the rank of the design matrix (number of linearly independent columns)
   193→    pub fn rank(&self) -> usize {
   194→        self.rank
   195→    }
   196→
   197→    /// Get degrees of freedom for error (n_obs - rank)
   198→    pub fn df_resid(&self) -> usize {
   199→        self.n_obs.saturating_sub(self.rank)
   200→    }
   201→}
   202→
   203→impl Fit for LmFit {
   204→    fn coefficients(&self) -> &[f64] {
   205→        &self.coefficients
   206→    }
   207→
   208→    fn fitted(&self) -> &[f64] {
   209→        &self.fitted_values
   210→    }
   211→
   212→    fn residuals(&self) -> &[f64] {
   213→        &self.residuals
   214→    }
   215→
   216→    fn summary(&self) -> ModelSummary {
   217→        use inference::{f_test_p_value, model_f_statistic, t_statistics, t_test_p_values};
   218→
   219→        // Calculate residual standard error: s² = RSS / (n - p)
   220→        let rss: f64 = self.residuals.iter().map(|r| r * r).sum();
   221→        let df_resid = self.df_resid() as f64;
   222→        let mse = if df_resid > 0.0 { rss / df_resid } else { 0.0 };
   223→        let residual_std_error = mse.sqrt();
   224→
   225→        // Calculate Total Sum of Squares (TSS) and R-squared
   226→        let y_mean: f64 = self
   227→            .fitted_values
   228→            .iter()
   229→            .zip(self.residuals.iter())
   230→            .map(|(fitted, resid)| fitted + resid) // y = fitted + residual
   231→            .sum::<f64>()
   232→            / self.n_obs as f64;
   233→
   234→        let tss: f64 = self
   235→            .fitted_values
   236→            .iter()
   237→            .zip(self.residuals.iter())
   238→            .map(|(fitted, resid)| {
   239→                let y = fitted + resid;
   240→                (y - y_mean).powi(2)
   241→            })
   242→            .sum();
   243→
   244→        let r_squared = if tss > 0.0 { 1.0 - rss / tss } else { 0.0 };
   245→
   246→        // Adjusted R-squared: 1 - (RSS/(n-p)) / (TSS/(n-1))
   247→        let n = self.n_obs as f64;
   248→        let p = self.rank as f64;
   249→        let adj_r_squared = if n > 1.0 && p > 0.0 {
   250→            1.0 - (rss / (n - p)) / (tss / (n - 1.0))
   251→        } else {
   252→            r_squared
   253→        };
   254→
   255→        // F-statistic for overall model significance
   256→        // RSS for null model (intercept only) equals TSS
   257→        let df_model = if self.rank > 1 { self.rank - 1 } else { 0 }; // exclude intercept
   258→        let f_statistic = if df_model > 0 {
   259→            model_f_statistic(rss, tss, df_model, self.df_resid())
   260→        } else {
   261→            0.0
   262→        };
   263→
   264→        let f_p_value = if df_model > 0 && self.df_resid() > 0 {
   265→            f_test_p_value(f_statistic, df_model as i32, self.df_resid() as i32)
   266→        } else {
   267→            1.0
   268→        };
   269→
   270→        // Calculate variance-covariance matrix: σ² * (X'X)^(-1)
   271→        // Compute X'X
   272→        let xtx = self.x_matrix.transpose() * &self.x_matrix;
   273→
   274→        // Compute (X'X)^(-1) - use QR decomposition for numerical stability
   275→        let qr = xtx.col_piv_qr();
   276→        let identity = Mat::identity(xtx.nrows(), xtx.ncols());
   277→        let xtx_inv = qr.solve(&identity);
   278→
   279→        // Standard errors are sqrt of diagonal elements of σ² * (X'X)^(-1)
   280→        let std_errors: Vec<f64> = (0..self.coefficients.len())
   281→            .map(|i| (mse * xtx_inv[(i, i)]).sqrt())
   282→            .collect();
   283→
   284→        let t_stats = t_statistics(&self.coefficients, &std_errors);
   285→        let p_values = t_test_p_values(&t_stats, self.df_resid() as i32);
   286→
   287→        let mut coefficient_rows = Vec::new();
   288→        for (i, &coef) in self.coefficients.iter().enumerate() {
   289→            let name = if i == 0 {
   290→                "Intercept".to_string()
   291→            } else {
   292→                format!("X{}", i)
   293→            };
   294→
   295→            coefficient_rows.push(CoefficientRow {
   296→                name,
   297→                estimate: coef,
   298→                std_error: std_errors[i],
   299→                t_value: t_stats[i],
   300→                p_value: p_values[i],
   301→            });
   302→        }
   303→
   304→        ModelSummary {
   305→            coefficients: coefficient_rows,
   306→            r_squared,
   307→            adj_r_squared,
   308→            residual_std_error,
   309→            f_statistic,
   310→            f_p_value,
   311→            df_model,
   312→            df_residual: self.df_resid(),
   313→        }
   314→    }
   315→}
   316→
   317→#[cfg(test)]
   318→mod tests {
   319→    use super::*;
   320→
   321→    #[test]
   322→    fn test_lm_fit_basic() {
   323→        // Simple 2x2 identity matrix with response
   324→        let x_data = vec![1.0, 0.0, 0.0, 1.0]; // 2x2 identity
   325→        let y_data = vec![1.0, 2.0];
   326→
   327→        let result = Lm::fit(&x_data, &y_data, 2, 2);
   328→        assert!(result.is_ok());
   329→
   330→        let fit = result.unwrap();
   331→        assert_eq!(fit.coefficients().len(), 2);
   332→        assert_eq!(fit.fitted().len(), 2);
   333→        assert_eq!(fit.residuals().len(), 2);
   334→        assert_eq!(fit.n_obs, 2);
   335→        assert_eq!(fit.rank, 2);
   336→    }
   337→
   338→    #[test]
   339→    fn test_lm_simple_regression() {
   340→        // Simple linear regression: y = 1 + 2*x + error
   341→        // Design matrix with intercept column
   342→        let x_data = vec![
   343→            1.0, 1.0, // [1, x1]
   344→            1.0, 2.0, // [1, x2]
   345→            1.0, 3.0, // [1, x3]
   346→        ];
   347→        let y_data = vec![3.0, 5.0, 7.0]; // 1 + 2*x
   348→
   349→        let result = Lm::fit(&x_data, &y_data, 3, 2);
   350→        assert!(result.is_ok());
   351→
   352→        let fit = result.unwrap();
   353→
   354→        // Check that we recovered the true coefficients (approximately)
   355→        let coefs = fit.coefficients();
   356→        assert!(
   357→            (coefs[0] - 1.0).abs() < 1e-10,
   358→            "Intercept should be ~1.0, got {}",
   359→            coefs[0]
   360→        );
   361→        assert!(
   362→            (coefs[1] - 2.0).abs() < 1e-10,
   363→            "Slope should be ~2.0, got {}",
   364→            coefs[1]
   365→        );
   366→
   367→        // Check dimensions
   368→        assert_eq!(fit.n_obs, 3);
   369→        assert_eq!(fit.rank, 2);
   370→    }
   371→
   372→    #[test]
   373→    fn test_lm_rank_deficient() {
   374→        // Rank deficient matrix: second column = 2 * first column
   375→        let x_data = vec![
   376→            1.0, 2.0, // [1, 2]
   377→            2.0, 4.0, // [2, 4]
   378→            3.0, 6.0, // [3, 6]
   379→        ];
   380→        let y_data = vec![1.0, 2.0, 3.0];
   381→
   382→        let result = Lm::fit(&x_data, &y_data, 3, 2);
   383→        assert!(result.is_ok());
   384→
   385→        let fit = result.unwrap();
   386→
   387→        // Matrix rank should be correctly detected as 1 (second column = 2 * first column)
   388→        assert_eq!(fit.n_obs(), 3);
   389→        assert_eq!(fit.rank(), 1); // Correctly detected rank-deficient matrix
   390→        assert_eq!(fit.df_resid(), 2); // 3 obs - 1 rank = 2 df
   391→
   392→        // The key is that coefficients should still be computed without crashing
   393→        assert_eq!(fit.coefficients().len(), 2);
   394→    }
   395→
   396→    #[test]
   397→    fn test_lm_summary() {
   398→        // Use a case with some residual variation for meaningful standard errors
   399→        let x_data = vec![
   400→            1.0, 1.0, // [1, x1]
   401→            1.0, 2.0, // [1, x2]
   402→            1.0, 3.0, // [1, x3]
   403→            1.0, 4.0, // [1, x4]
   404→        ];
   405→        let y_data = vec![2.1, 4.0, 5.9, 8.1]; // approximately y = 2*x with some noise
   406→
   407→        let fit = Lm::fit(&x_data, &y_data, 4, 2).unwrap();
   408→        let summary = fit.summary();
   409→
   410→        assert!(!summary.coefficients.is_empty());
   411→        assert_eq!(summary.coefficients[0].name, "Intercept");
   412→        assert_eq!(summary.coefficients.len(), 2);
   413→
   414→        // Verify that standard errors are computed (not zero or placeholder)
   415→        for coef_row in &summary.coefficients {
   416→            assert!(
   417→                coef_row.std_error > 0.0,
   418→                "Standard error should be positive: {}",
   419→                coef_row.std_error
   420→            );
   421→            assert!(
   422→                coef_row.p_value >= 0.0 && coef_row.p_value <= 1.0,
   423→                "P-value should be between 0 and 1"
   424→            );
   425→        }
   426→    }
   427→
   428→    #[test]
   429→    fn test_statistical_inference_known_case() {
   430→        // Simple case: y = 1 + 2*x (exact linear relationship)
   431→        let x_data = vec![
   432→            1.0, 1.0, // [1, x1] where x1 = 1
   433→            1.0, 2.0, // [1, x2] where x2 = 2
   434→            1.0, 3.0, // [1, x3] where x3 = 3
   435→        ];
   436→        let y_data = vec![3.0, 5.0, 7.0]; // y = 1 + 2*x
   437→
   438→        let fit = Lm::fit(&x_data, &y_data, 3, 2).unwrap();
   439→        let summary = fit.summary();
   440→
   441→        // With perfect linear fit, residuals should be very small
   442→        assert!(
   443→            fit.residuals().iter().all(|&r| r.abs() < 1e-10),
   444→            "Residuals should be near zero for perfect fit"
   445→        );
   446→
   447→        // Coefficients should be exactly recovered
   448→        let coefs = fit.coefficients();
   449→        assert!((coefs[0] - 1.0).abs() < 1e-10, "Intercept should be 1.0");
   450→        assert!((coefs[1] - 2.0).abs() < 1e-10, "Slope should be 2.0");
   451→
   452→        // For perfect fit with 1 degree of freedom, statistics should be extreme
   453→        assert_eq!(summary.coefficients.len(), 2);
   454→        println!("Summary: {:?}", summary);
   455→    }
   456→
   457→    #[test]
   458→    fn test_enhanced_summary_statistics() {
   459→        // Test with data that has some variation for meaningful R²
   460→        let x_data = vec![
   461→            1.0, 1.0, // [1, x1]
   462→            1.0, 2.0, // [1, x2]
   463→            1.0, 3.0, // [1, x3]
   464→            1.0, 4.0, // [1, x4]
   465→            1.0, 5.0, // [1, x5]
   466→        ];
   467→        let y_data = vec![2.1, 3.9, 6.1, 7.9, 10.1]; // approximately y = 2*x with noise
   468→
   469→        let fit = Lm::fit(&x_data, &y_data, 5, 2).unwrap();
   470→        let summary = fit.summary();
   471→
   472→        // Verify enhanced summary includes all R-parity statistics
   473→        assert!(
   474→            summary.r_squared >= 0.0 && summary.r_squared <= 1.0,
   475→            "R² should be between 0 and 1"
   476→        );
   477→        assert!(
   478→            summary.adj_r_squared <= summary.r_squared,
   479→            "Adjusted R² should be ≤ R²"
   480→        );
   481→        assert!(
   482→            summary.residual_std_error > 0.0,
   483→            "Residual standard error should be positive"
   484→        );
   485→        assert!(
   486→            summary.f_statistic >= 0.0,
   487→            "F-statistic should be non-negative"
   488→        );
   489→        assert!(
   490→            summary.f_p_value >= 0.0 && summary.f_p_value <= 1.0,
   491→            "F p-value should be between 0 and 1"
   492→        );
   493→        assert_eq!(
   494→            summary.df_model, 1,
   495→            "Model should have 1 degree of freedom (excluding intercept)"
   496→        );
   497→        assert_eq!(
   498→            summary.df_residual, 3,
   499→            "Should have 3 residual degrees of freedom (5 obs - 2 params)"
   500→        );
   501→
   502→        // With decent fit, R² should be reasonably high
   503→        assert!(
   504→            summary.r_squared > 0.8,
   505→            "R² should be high for this near-linear relationship: {}",
   506→            summary.r_squared
   507→        );
   508→
   509→        println!("Enhanced summary statistics:");
   510→        println!("R² = {:.6}", summary.r_squared);
   511→        println!("Adj R² = {:.6}", summary.adj_r_squared);
   512→        println!("Residual SE = {:.6}", summary.residual_std_error);
   513→        println!("F-statistic = {:.6}", summary.f_statistic);
   514→        println!("F p-value = {:.6}", summary.f_p_value);
   515→    }
   516→
   517→    #[test]
   518→    fn test_multicollinearity_debug() {
   519→        // Test with non-collinear data to check if our fix works
   520→        let n_obs = 8;
   521→        let x1_values: Vec<f64> = (1..=n_obs).map(|i| i as f64).collect();
   522→        let x2_values: Vec<f64> = (1..=n_obs)
   523→            .map(|i| (i as f64) * 0.3 + 0.1 * (i as f64).powi(2))
   524→            .collect();
   525→        let y_values: Vec<f64> = x1_values
   526→            .iter()
   527→            .zip(x2_values.iter())
   528→            .map(|(&x1, &x2)| 2.0 + 1.5 * x1 + 0.8 * x2 + 0.1 * x1 * x2.sin())
   529→            .collect();
   530→
   531→        // Design matrix: [1, x1, x2] - now without perfect multicollinearity
   532→        let mut x_data = Vec::with_capacity(n_obs * 3);
   533→        for i in 0..n_obs {
   534→            x_data.push(1.0); // intercept
   535→            x_data.push(x1_values[i]); // x1
   536→            x_data.push(x2_values[i]); // x2
   537→        }
   538→
   539→        println!("=== Multiple Regression Debug ===");
   540→        println!("x1: {:?}", x1_values);
   541→        println!("x2: {:?}", x2_values);
   542→        println!("x2 is not perfectly correlated with x1");
   543→
